CREATE TABLE public.crm_referral_partners (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), tenant_id UUID NOT NULL REFERENCES public.tenants(id) ON DELETE CASCADE, partner_code TEXT NOT NULL, partner_name TEXT NOT NULL, partner_email TEXT, partner_phone TEXT, partner_type TEXT DEFAULT 'contractor', status public.crm_partner_status NOT NULL DEFAULT 'pending', tier public.crm_partner_tier NOT NULL DEFAULT 'standard', payout_type public.crm_payout_type NOT NULL DEFAULT 'fixed_fee', payout_value NUMERIC(10,2) NOT NULL DEFAULT 0, payout_threshold NUMERIC(10,2) DEFAULT 0, payout_schedule TEXT DEFAULT 'monthly', payment_method TEXT, payment_details JSONB DEFAULT '{}', tax_id TEXT, company_name TEXT, website TEXT, notes TEXT, total_clicks INTEGER NOT NULL DEFAULT 0, total_signups INTEGER NOT NULL DEFAULT 0, total_paid_out NUMERIC(10,2) NOT NULL DEFAULT 0, total_earned NUMERIC(10,2) NOT NULL DEFAULT 0, is_internal_user BOOLEAN NOT NULL DEFAULT false, internal_user_id UUID REFERENCES auth.users(id) ON DELETE SET NULL, created_at TIMESTAMPTZ NOT NULL DEFAULT NOW(), updated_at TIMESTAMPTZ NOT NULL DEFAULT NOW(), UNIQUE(tenant_id, partner_code)); CREATE TABLE public.crm_referral_links (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), tenant_id UUID NOT NULL REFERENCES public.tenants(id) ON DELETE CASCADE, partner_id UUID NOT NULL REFERENCES public.crm_referral_partners(id) ON DELETE CASCADE, link_code TEXT NOT NULL UNIQUE, utm_source TEXT, utm_medium TEXT, utm_campaign TEXT, landing_page TEXT DEFAULT '/signup', is_active BOOLEAN NOT NULL DEFAULT true, click_count INTEGER NOT NULL DEFAULT 0, signup_count INTEGER NOT NULL DEFAULT 0, created_at TIMESTAMPTZ NOT NULL DEFAULT NOW()); CREATE TABLE public.crm_referral_signup_events (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), tenant_id UUID NOT NULL REFERENCES public.tenants(id) ON DELETE CASCADE, partner_id UUID REFERENCES public.crm_referral_partners(id) ON DELETE SET NULL, link_id UUID REFERENCES public.crm_referral_links(id) ON DELETE SET NULL, event_type TEXT NOT NULL, visitor_id TEXT, session_id TEXT, ip_hash TEXT, user_agent TEXT, referrer_url TEXT, utm_source TEXT, utm_medium TEXT, utm_campaign TEXT, created_at TIMESTAMPTZ NOT NULL DEFAULT NOW());